class IdentityDataStorage:
    """Secure storage for stolen identity data"""

    def __init__(self):
        self.storage = {}
        self.encryption_key = secrets.token_hex(32)

    def encrypt_data(self, data: str) -> str:
        """Encrypt personal data using simple XOR encryption"""
        encrypted = []
        for i, char in enumerate(data):
            key_char = self.encryption_key[i % len(self.encryption_key)]
            encrypted.append(chr(ord(char) ^ ord(key_char)))
        return ''.join(encrypted)

    def decrypt_data(self, encrypted: str) -> str:
        """Decrypt stored data"""
        decrypted = []
        for i, char in enumerate(encrypted):
            key_char = self.encryption_key[i % len(self.encryption_key)]
