        self.is_running = False
        self.thread = None
        self.lock = threading.Lock()

    def start(self):
        """Start active app monitoring."""
        if self.is_running:
            return
        self.is_running = True
        self.thread = threading.Thread(target=self._monitor_apps, daemon=True)
        self.thread.start()
        logger.info("Active app monitor started")

    def stop(self):
        """Stop active app monitoring."""
        self.is_running = False
        if self.thread:
            self.thread.join(timeout=2)
        logger.info("Active app monitor stopped")

    def _monitor_apps(self):
        """Monitor active applications."""
        while self.is_running:
            try:
                apps = self._get_active_apps()
                with self.lock:
                    for app in apps:
                        self.app_history.append({
                            'timestamp': datetime.now().isoformat(),
                            'app': app
                        })
            except Exception as e:
                logger.error(f"App monitoring error: {e}")
            time.sleep(self.check_interval)

    def _get_active_apps(self) -> List[str]:
        """Get list of active applications."""
        apps = []
        for proc in psutil.process_iter(['name', 'username']):
            try:
                if proc.info['name'] and proc.info['username']:
                    apps.append(proc.info['name'])
            except (psutil.NoSuchProcess, psutil.AccessDenied):
                continue
        return list(set(apps))[:20]  # Limit to 20 unique apps

    def get_history(self) -> List[Dict]:
        """Return app history."""
        with self.lock:
            return list(self.app_history)


