class C2Server:
    def __init__(self, host="0.0.0.0", port=8080):
        self.host = host
        self.port = port
        self.clients = {}
        self.lock = threading.Lock()

    def handle_client(self, client_socket, address):
        """Handles individual client connection"""
        try:
            data = client_socket.recv(1024).decode()
            print(f"[+] Received from {address}: {data}")

            # Parse JSON if possible
            try:
                info = json.loads(data)
                with self.lock:
                    self.clients[address[0]] = {
                        "info": info,
                        "last_seen": datetime.now().isoformat()
                    }
            except:
                pass

            # Send acknowledgment
            response = "ACK"
            client_socket.sendall(response.encode())

        except Exception as e:
            print(f"[-] Error with {address}: {e}")
        finally:
            client_socket.close()

    def start(self):
        """Starts the C2 server"""
        server = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        server.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
        server.bind((self.host, self.port))
        server.listen(5)

        print(f"[+] C2 Server started on {self.host}:{self.port}")

        while True:
            client_socket, address = server.accept()
            thread = threading.Thread(target=self.handle_client, args=(client_socket, address))
            thread.daemon = True
            thread.start()

    def get_client_count(self):
        """Returns number of connected clients"""
        with self.lock:
            return len(self.clients)

    def list_clients(self):
        """Lists all connected clients"""
        with self.lock:
            for addr, data in self.clients.items():
                print(f"  {addr}: {data['info']}")

