        summary.append(f"Git Credentials: {len(self.collected_data['git_credentials'])}")
        summary.append(f"Dotenv Files: {len(self.collected_data['dotenv_files'])}")
        summary.append(f"Recent Files: {len(self.collected_data['recent_files'])}")
        summary.append(f"Running Processes: {len(self.collected_data['running_processes'])}")

        return '\n'.join(summary)


