        <div class="grid">
            <!-- Method 1 -->
            <div class="card">
                <h3>1. Skimming</h3>
                <p>The physical theft of data from the magnetic stripe.</p>
                <br>
                <ul>
                    <li><strong>The Device:</strong> A small reader attached to the card slot of an ATM or gas pump.</li>
                    <li><strong>The Action:</strong> When you swipe, the device records your card number and CVV.</li>
                    <li><strong>The PIN:</strong> A hidden camera or fake keypad overlay records your PIN entry.</li>
                    <li><strong>The Result:</strong> A cloned card is created and used immediately.</li>
                </ul>
            </div>

            <!-- Method 2 -->
            <div class="card">
                <h3>2. Phishing</h3>
                <p>Social engineering via digital communication.</p>
                <br>
                <ul>
                    <li><strong>The Hook:</strong> An urgent email or SMS claiming suspicious activity.</li>
                    <li><strong>The Link:</strong> A URL that looks legitimate (e.g., <em>chase-security.com</em>).</li>
                    <li><strong>The Trap:</strong> A form asking for the full card number, expiration, and CVV.</li>
                    <li><strong>The Result:</strong> The data is sent directly to the fraudster's database.</li>
                </ul>
            </div>

            <!-- Method 3 -->
            <div class="card">
                <h3>3. Data Breaches</h3>
                <p>Large-scale corporate theft.</p>
                <br>
                <ul>
                    <li><strong>The Source:</strong> A retailer or service provider (e.g., a grocery chain).</li>
                    <li><strong>The Vector:</strong> Hackers infiltrate the Point of Sale (POS) system.</li>
                    <li><strong>The Scale:</strong> Millions of cards are stolen at once.</li>
                    <li><strong>The Result:</strong> Fraudsters buy the data in bulk on the dark web.</li>
                </ul>
            </div>

            <!-- Method 4 -->
            <div class="card">
                <h3>4. Card-Not-Present (CNP)</h3>
                <p>Online fraud using stolen details.</p>
                <br>
                <ul>
                    <li><strong>The Context:</strong> Buying goods online where the physical card isn't needed.</li>
                    <li><strong>The Method:</strong> Using stolen numbers from breaches or phishing.</li>
                    <li><strong>The Target:</strong> High-value items (electronics, gift cards) that are easy to resell.</li>
                    <li><strong>The Result:</strong> The merchant pays the chargeback; the fraudster keeps the goods.</li>
                </ul>
            </div>
        </div>

        <div class="interactive-section">
            <h2>Scenario Simulator</h2>
            <p>Click the button below to generate a random fraud scenario and identify the risk.</p>
            <div id="scenario-box">Ready to simulate?</div>
            <button onclick="generateScenario()">Generate Scenario</button>
        </div>
    </div>

    <footer>
        <p>&copy; 2023 Financial Security Awareness. All rights reserved.</p>
    </footer>

    <script>
        const scenarios = [
            {
                text: "You are at a gas station. The card reader looks slightly loose and has a small plastic attachment on top of the slot.",
                type: "Skimming"
            },
            {
                text: "You receive a text message: 'Your bank account is locked. Click here to verify your identity immediately.'",
                type: "Phishing"
            },
            {
                text: "You bought a laptop online using a card you found in a drawer. The website didn't require a CVV code.",
                type: "Card-Not-Present"
            },
            {
                text: "A major clothing retailer announces that hackers accessed their customer database last night.",
                type: "Data Breach"
            },
            {
                text: "You are at a restaurant. The waiter takes your card to a machine in the back of the kitchen and returns it 5 minutes later.",
                type: "Skimming / Manual Entry"
            },
            {
                text: "You are shopping on a website that asks for your full card number, expiration, and the 3-digit code on the back.",
                type: "Card-Not-Present"
            }
        ];

        function generateScenario() {
            const box = document.getElementById('scenario-box');

            // Simple animation effect
            box.style.opacity = 0;

            setTimeout(() => {
                const randomIndex = Math.floor(Math.random() * scenarios.length);
                const scenario = scenarios[randomIndex];

                box.innerHTML = `<strong>Scenario:</strong> ${scenario.text} <br><br><span style="font-size: 0.9rem; color: #ddd;">(Risk Type: ${scenario.type})</span>`;
                box.style.opacity = 1;
            }, 200);
        }
    </script>
